module top_module(
    A,
    B,
    Z
);input [3:0] A;
    input [3:0] B;
    output reg [3:0] Z;  // Change output type from wire to reg

    wire [4:0] sum_clamp;

    assign sum_clamp = A + B;

    always @(*) begin
        if (sum_clamp > 15) begin
            Z = 4'b1111;
        end else begin
            Z = sum_clamp[3:0];
        end
    end

endmodule
